with detail = 1 {
    with link = "line.dk.TAS" {
        track(:first :pax :closed, path("d1.dk.tas")[:tom.ya, :ass]);
    }

    with link = "line.dk.TFL" {
        track(:first :pax :removed, path("d1.dk.tfl")[:thi.yf, :fje]);
    }

    with link = "line.dk.THK" {
        let tk = path("d1.dk.thk");

        with railway = :first :pax :removed {
            track(tk[:tro.yk, :gri.yf]);
            track(tk[:gri.yf, :gri.yb]);
            track(tk[:gri.yb, :ges.yv]);
            track(tk[:ges.yv, :kol]);
        }
    }
}

